import 'package:cached_network_image/cached_network_image.dart';import 'package:flutter/material.dart';import '../../models/sponsor_banner_model.dart';
class SponsorBannerList extends StatelessWidget{final List<SponsorBannerModel> banners;const SponsorBannerList({super.key,required this.banners});@override Widget build(BuildContext c){final visible=banners.where((b)=>b.imageUrl!=null&&b.imageUrl!.isNotEmpty).toList(); if(visible.isEmpty)return const SizedBox.shrink(); return SizedBox(height:120,child:ListView.separated(scrollDirection:Axis.horizontal,padding:const EdgeInsets.symmetric(horizontal:16),itemCount:visible.length,separatorBuilder:(_,__)=>const SizedBox(width:12),itemBuilder:(c,i)=>ClipRRect(borderRadius:BorderRadius.circular(16),child:CachedNetworkImage(imageUrl:visible[i].imageUrl!,width:260,fit:BoxFit.cover,errorWidget:(_,__,___)=>const SizedBox.shrink()))));}}
